external_knowledge:
- A tag_id of 0 can be seen as a beacon or marker that signifies a special group or category of campaigns.; 
- The phrase "embarked on the journey" refers to campaigns that have been initiated with a specific tag or identifier.; 
- The "seas they sail" represent the broad categories within which these campaigns operate.; 
- "The depth of their pledges" is a metaphor for the financial commitment required from supporters to receive a reward.; 
- "The treasures they promise" symbolize the rewards that backers will receive.; 
- "The horizon they aim to reach" is a poetic way to describe the estimated delivery date of these rewards.

sql:
SELECT name, number_of_backers
FROM campaigns
WHERE number_of_backers < (
  SELECT AVG(number_of_backers)
  FROM campaigns
);

SELECT b.backer_name, b.email
FROM backers b
WHERE b.backer_id NOT IN (SELECT DISTINCT p.backer_id FROM pledges p);

SELECT c.campaign_id, c.name, c.status
FROM campaigns c
WHERE c.status = 'active' AND c.campaign_id NOT IN (
    SELECT u.campaign_id
    FROM updates u
);

SELECT update_id 
FROM updates 
WHERE campaign_id = 1 AND creator_id = 1;

SELECT campaign_id, COUNT(DISTINCT backer_id) AS total_unique_supporters
FROM pledges
GROUP BY campaign_id;
